var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"이상하군. 침식체들이 사라진 것도 모자라 CSE 레벨이 정상 수치로 돌아왔어.","JPN":"おかしい。侵食体が消えただけではなく、CSEレベルが正常値に戻った。","ENG":"Strange. Not only did the C.O.s vanish, but the CSE levels are back to normal.","TWN":"好奇怪。侵蝕體消失不見了，CSE等級也恢復到了正常數值。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"관리국의 대처가 있었다고 해도… 너무 갑작스러운데.","JPN":"管理局の対処があったとしても……突然すぎる。","ENG":"Even if the Administration stepped in... this happened too fast.","TWN":"即使有管理局的應對……也太突然了。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"기사님! 크, 큰일입니다!","JPN":"騎士様！　た、大変です！","ENG":"Knight! There's a problem, a big one!","TWN":"騎士小姐！出、出大事了！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"원장님? 침식 경보가 해제되었다고는 해도 이렇게 돌아다니는 건 위험합니다.","JPN":"院長？　侵食警報が解除されたとはいえ、外を歩き回るのは危険です。","ENG":"Headmaster? The Corruption alert might be lifted, but it's still dangerous to be out here.","TWN":"院長？雖然侵蝕警報已經解除，但這樣到處走動還是很危險的。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"그, 그게 중요한 게 아닙니다.","JPN":"そ、それどころではありません。","ENG":"Th-that's not the issue!","TWN":"那，那不是重點。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"엠마가… 엠마가 사라졌어요!","JPN":"エマが……エマがいないんです！","ENG":"Emma... Emma's gone!","TWN":"艾瑪……艾瑪消失了！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"읍! 으읍! 으으읍!!","JPN":"うっ！　うぶっ！　うぶぶっ！！","ENG":"Mmph! Mmmph! Mmmmmmph!!","TWN":"唔！嗚嗚！嗚嗚嗚！！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L19_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"거 더럽게 시끄럽네. 얌전히 좀 있어라!","JPN":"うるさいな。大人しくしろ！","ENG":"Man, you're noisy. Sit still, would ya?","TWN":"真是吵死了。安靜點吧！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_B","text":{"KOREA":"형님. 괜찮을까요? 이 꼬맹이랑 같이 있던 여자. 저번에 그 망나니잖아요.","JPN":"兄貴。いいんですか？　このガキと一緒にいたあの女、この前のあいつじゃないですか。","ENG":"Sir, are we sure this is okay? That girl she was with, she's that psycho, right?","TWN":"大哥，沒問題嗎？和這個小鬼在一起的女人，就是上次那個混蛋啊。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BULLY_PRIDE_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_B","text":{"KOREA":"최근 블랙 네트워크에서 언급된 녀석이랑 동일 인물 같은데, 혹시 잘못 건드리면…….","JPN":"最近ブラックネットワークでうわさのやつと同一人物っぽいけど、下手したら……","ENG":"Pretty sure she's the one they've been talking about on the Dark Network. If we pissed her off...","TWN":"最近在黑色網路上提到的傢伙好像是同一個人，萬一惹錯了……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BULLY_PRIDE_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"그 로브 쓴 년이 망나니여봤자 우리 보스만 하겠냐?","JPN":"ローブの女が暴れたところで、うちのボスには敵わねえだろ。","ENG":"So what if she's nuts? You think she's tougher than our boss?","TWN":"那個穿袍子的傢伙再怎麼胡鬧，也比不上我們老闆吧？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BULLY_PRIDE_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"개죽음당하기 싫으면 그냥 얌전히 시키는 대로 해!","JPN":"死にたくなけりゃ黙って言う通りにしろ！","ENG":"Unless you want to die, shut up and do as you're told!","TWN":"不想白白送命的話，就乖乖聽話！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BULLY_PRIDE_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"읍! 으으읍!!","JPN":"うっ！　うぶぶ！！","ENG":"Mmmph! Mmmmmmph!!","TWN":"唔！嗚嗚唔！！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"야, 인마. 그러게 전에 만났을 때 얌전히 굴었으면 좋았잖아.","JPN":"ったく、だからこの前大人しくすりゃよかったんだ。","ENG":"Hey, kid. You should've did what we asked when we first met.","TWN":"喂，夥計。早知道上次見面時乖乖聽話就好了吧。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"왜 귀찮게 굴어서 서로 피곤하게 만들어?","JPN":"抵抗するからお互い面倒なことになるんだぞ？","ENG":"Look at this mess. You're making this harder for both of us.","TWN":"為什麼要麻煩自己，讓彼此都累呢？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_B","text":{"KOREA":"혀, 형님…….","JPN":"あ、兄貴……","ENG":"S-sir...","TWN":"老……老大……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"BULLY_PRIDE_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"뭐! 너도 이제 나 무시하냐?","JPN":"んだよ！　お前まで俺のこと舐めてんのか！","ENG":"What?! You ignoring me too now?","TWN":"什麼！你也開始看我沒有嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"BULLY_PRIDE_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"끄아아아악-!!","JPN":"くわああっ！！","ENG":"Gaaaah!","TWN":"呃啊啊啊-！！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MONSTER_MOVEMENT_03"},{"id":"L38_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"괜찮나, 엠마?","JPN":"無事か、エマ？","ENG":"Emma, are you okay?","TWN":"沒事嗎，艾瑪？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L39_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"기, 기사니이임-!!","JPN":"き、騎士様あぁ！！","ENG":"Miss Knight!!","TWN":"騎，騎士姊姊-！！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"뭐, 뭐야. 어떻게 이렇게 빨리 쫓아온 거야?","JPN":"な、なんだ。なんでこんなに早く追ってこられた？","ENG":"W-what the–?! How did she catch up so fast?!","TWN":"什、什麼啊。怎麼這麼快就追上來了？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"오히려 이쪽에서 묻고 싶군. 대놓고 흔적을 남겨 함정인가 싶었는데.","JPN":"逆に聞きたいな。わかりやすい痕跡を残すものだから、罠かと思ったが。","ENG":"I should be asking you. You left such obvious tracks I thought it was a trap.","TWN":"我倒是想問問你。故意留下痕跡，是想設陷阱嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"설마 아무런 대책이 없었던 건가?","JPN":"まさか、何も対策を立ててなかったのか？","ENG":"Don't tell me you actually had no plan?","TWN":"難道你沒有任何對策嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"시끄러…! 이년이나 저년이나 계속 깔보는 말투로 말하긴……!","JPN":"うるせぇ……！　どいつもこいつも、俺を舐めやがって……！","ENG":"Shut up...! You think you're better than me?! You and that brat talking like you're above it all...!","TWN":"閉嘴……！不管是你還是她，總是用那種輕蔑的語氣說話……！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"날 무시하지 말라고-!!","JPN":"俺を見くびるんじゃねー！！","ENG":"Stop looking down on me!!","TWN":"別小看我-！！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L49_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"계속 할 건가?","JPN":"まだ続けるか？","ENG":"Still wish to continue?","TWN":"要繼續嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_B","text":{"KOREA":"하, 항복입니다…….","JPN":"こ、降参です……","ENG":"W-we surrender...","TWN":"哈，我投降……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"완전, 완전 멋있어요. 기사님!","JPN":"すごく、すっごく格好いいです、騎士様！","ENG":"That, that was amazing!","TWN":"超，超級帥，騎士姊姊！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"조디악 나이츠의 기사님들은 전부 그런 식으로 싸우는 건가요?","JPN":"ゾディアックナイツの騎士様たちって、みんなそうやって戦うんですか？","ENG":"Is that how all Zodiac Knights fight?","TWN":"十二宮騎士團的騎士們都是這樣戰鬥的嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"딱히 대단할 건 없다. 내 검술은 다른 사람을 모방하는 데에 그쳤거든.","JPN":"別にすごくはない。私の剣術は人の技を模倣しているにすぎないのでな。","ENG":"It's nothing special. My swordsmanship is just an imitation.","TWN":"沒什麼特別的，我的劍術只是模仿其他人而已。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……아직 발끝도 못 따라가지만.","JPN":"……まだ足元にも及ばない。","ENG":"...I still haven't caught up to him.","TWN":"……還遠遠趕不上呢。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"흉내? 혹시 오빠분을 말씀하시는 건가요?","JPN":"真似？　もしかして、お兄さんのことですか？","ENG":"An imitation? You mean your brother?","TWN":"模仿？你是在說哥哥嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"뭐?","JPN":"え？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"아아! 성이 같을 때부터 혹시나 싶었는데, 역시 기사님은 그 분의 동생이셨군요?","JPN":"あ～！　家名が同じだからまさかと思ってたけど、やっぱりあの人の妹さんなんですね！","ENG":"Oh! I suspected it because you share a surname, but you really are his sister!","TWN":"啊啊！從姓氏相同的時候就有些懷疑，果然你是那位的妹妹嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"남매분께 같은 도움을 받다니. 어쩜, 이런 운명 같은 일이!","JPN":"兄妹に助けられるなんて、運命みたい！","ENG":"I can't believe I was saved by both siblings. It's like fate or something!","TWN":"竟然能從兄妹那裡得到同樣的幫助。哎呀，這真是命中註定的事情啊！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"엠마, 너… 오빠를 알고 있는 건가?","JPN":"エマ、君は……兄と知り合いなのか？","ENG":"Emma, wait... You knew my brother?","TWN":"艾瑪，你……認識哥哥嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"어… 아뇨? 그냥 예전에 난민지구에 오셨을 때 도움을 받은 게 전부예요.","JPN":"え……いえ？　前に、お兄さんが難民地区に来た時、ちょっと助けてもらっただけです。","ENG":"Uh... no? Just met him once when he came to the refugee district and helped out.","TWN":"呃…沒有？只是以前你來難民區時，我得到了一些幫助而已。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"나쁜 아저씨들을 상대로 막 요렇게 검을 휘두르시는데, 그 모습이 어찌나 멋있던지!","JPN":"悪いおじさんたちに、こうやって剣を振ってて、すごく格好よかった！","ENG":"He was fighting off bad guys like this, swinging his sword, and it was sooo cool!","TWN":"對那些壞叔叔揮舞著劍的樣子，真是太帥了！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"기, 기사님? 제 어깨는 왜…….","JPN":"き、騎士様？　なんで肩を掴んで……","ENG":"Miss Knight? Why are you grabbing my shoulder...?","TWN":"騎，騎士姊姊？為什麼抓著我的肩膀……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"달리, 달리 알고 있는 건 없는 건가?","JPN":"他に、他に知っていることはないか？","ENG":"Do you... Do you remember anything else about him?","TWN":"還有其他知道的嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"사소한 거라도 좋아! 기억나는 게 있다면, 뭐라도 좋으니까…!!","JPN":"どんなに些細なことでも構わない！　覚えていることがあれば、なんでもいいから……！！","ENG":"Even something small! Anything at all, please...!","TWN":"哪怕是小事也好！如果有記得的事情，什麼都好……！！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"그, 그게… 잠시만요? 분명 대화 몇 마디를 주고받긴 했었는데.","JPN":"そ、その……ちょっと待ってください。確か、少し話をしたけど……","ENG":"Um, gimme a second... I think we talked a bit.","TWN":"那、那個……等一下？我們確實聊了幾句。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"그게…… 아!","JPN":"それが……あ！","ENG":"Uh... Oh!","TWN":"那個……啊！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"분명, <color=#ffd34c>고향</color>으로 간다고 말씀하셨어요!","JPN":"確か、<color=#ffd34c>故郷</color>に行くって言ってました！","ENG":"He said he was heading <color=#ffd34c>home</color>!","TWN":"他說要回<color=#ffd34c>故鄉</color>！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_B","text":{"KOREA":"혀, 형님… 정신 좀 차려 보세요.","JPN":"あ、兄貴……しっかりしてください。","ENG":"S-sir... Wake up.","TWN":"大哥……你醒醒。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_B","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP"},{"id":"L28_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"끄윽… 야, 나 얼마나 잠들어 있었냐?","JPN":"くっ……おい、俺……どれぐらい寝てたんだ？","ENG":"Urgh... How long was I out?","TWN":"呃……喂，我睡了多久？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":{"char_id":"BULLY_PRIDE_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_B","text":{"KOREA":"한 시간 좀 안됐어요. 이제 그 로브 쓴 년도 없으니 일어나셔도 돼요.","JPN":"1時間ちょっとです。あのローブの女もいないからもう起きても大丈夫ですよ。","ENG":"Not even an hour. That girl in the robe is gone, so it's safe to get up.","TWN":"不到一個小時。現在那個穿披風的傢伙也不在了，你可以起來了。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":{"char_id":"BULLY_PRIDE_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"크윽…! 빌어먹을!!","JPN":"くっ……！　ちくしょう！！","ENG":"Ugh...! Damn it!","TWN":"呃……！可惡！！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":{"char_id":"BULLY_PRIDE_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"더는 못해먹어!","JPN":"やってらんねぇ！！","ENG":"Screw this!","TWN":"我再也幹不下去了！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"갑자기 나타난 년한테 조직은 뺏기고, 계집년한테는 두 번씩이나 얻어맞고!","JPN":"組織は突然現れた奴らに奪われて、あの女には2回も殴られて！","ENG":"I lost the gang to some random chick, and got beat down twice by a damn girl!","TWN":"突然出現的女人搶走了組織，還被那個女人打了兩次！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"이게 대체 무슨 꼴이야?","JPN":"なんのざまだよ！","ENG":"Just look at us!","TWN":"這到底是怎麼回事？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"유괴해서 협박하는 것도 아니고, 보육원 애새끼 하나 납치하라는 게 말이냐고!","JPN":"誘拐して脅すわけでもねぇのに、施設のガキ1人掻っ攫えって！","ENG":"We kidnapped a kid from an orphanage. What kind of job even is this?!","TWN":"這不是綁架和威脅，而是讓我們去綁架一個孤兒院的小孩，這像什麼樣子！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_B","text":{"KOREA":"그럼 어떡해요. 조그만 년이 피도 눈물도 없는데…….","JPN":"仕方ないじゃないですか。あのちっちゃいの、血の涙もないやつだから……","ENG":"What else could we do? That little brat's got no mercy at all...","TWN":"那怎麼辦呢。那個小丫頭真是無情無義……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BULLY_PRIDE_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"때려치워! 조직이고 나발이고, 원래 밑바닥에서부터 시작한 인생이야.","JPN":"ええい、全部やめちまえ！　もともと泥沼から這い上がってきた人生だ。","ENG":"I'm done! Screw the gang! I came from nothing, and I'll start over from nothing!","TWN":"不幹了！什麼組織什麼鬼，我本來就是從底層開始的生活。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BULLY_PRIDE_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"처음부터 다시 시작하면 그만이라고!!","JPN":"最初からやり直せばいいだけなんだよ！","ENG":"I'll just rebuild from the ground up!","TWN":"從頭再來就行了！！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BULLY_PRIDE_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NPC_NULL","text":{"KOREA":"헤에~? 뭐야, 아저씨들. 설마 배신하려는 거야?","JPN":"へえ～　何、おじさんたち。まさか裏切るの？","ENG":"Hmm? What's this, boys? You're not thinking of betraying me, are you?","TWN":"嘿～？什麼呀，叔叔們。難道要背叛嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BULLY_PRIDE_NPC_B","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_SCISSORS_IN_TRAILER_1"},{"id":"L44_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NPC_NULL","text":{"KOREA":"아니지, 아니지. 내가 잘못 들은 거지? 응?","JPN":"違うよね？　アタシの聞き間違いだよね？　ね？","ENG":"No way. I must've misheard, right?","TWN":"不對，不對。我聽錯了吧？嗯？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BULLY_PRIDE_NPC_B","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_SCISSORS_IN_TRAILER_2"},{"id":"L46_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"보, 보스? 여긴 어떻게?","JPN":"ボ、ボス？　ここにはどうやって？","ENG":"B-boss?! What are you doing here?","TWN":"老、老闆？你怎麼會在這裡？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NPC_NULL","text":{"KOREA":"재밌어 보이니까 구경 왔어! 나는, 나는~? 궁금한 거 못 참거든!","JPN":"面白そうだから見に来たの！　アタシはねぇ～、気になるの我慢できないから！","ENG":"It looked fun, so I dropped by! You see, I can't help myself when it comes to things I'm curious about!","TWN":"看起來很有趣，所以我來看看！我，我呢~？我可是忍不住好奇心的！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_SCISSORS_IN_TRAILER_3"},{"id":"L48_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NPC_NULL","text":{"KOREA":"그런데~. 둘이서 작당모의하고. 안 되지, 응?","JPN":"それなのに～、二人で悪巧みしてて、ダメでしょ？","ENG":"But you two... Scheming behind my back? Tsk, tsk.","TWN":"不過～你們兩個在一起密謀。這樣不行喔，嗯？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_SCISSORS_IN_TRAILER_4"},{"id":"L49_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NPC_NULL","text":{"KOREA":"내가 준 임무도 실패했으면서~.","JPN":"アタシがお願いした任務も失敗したくせに～","ENG":"And you couldn't even finish the job I gave you.","TWN":"我交給你的任務也失敗了～"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NPC_NULL","face":"UNIT_LAUGH"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_SCISSORS_IN_TRAILER_5"},{"id":"L50_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_B","text":{"KOREA":"죄, 죄송합니다. 보스. 그 년이 어떻게 알았는지 순식간에 추격해서…….","JPN":"も、申し訳ございません、ボス。あの女、どうやってわかったのか、あっという間に追撃してきて……","ENG":"S-sorry, boss. That girl somehow tracked us down instantly...","TWN":"對，對不起。老大。那個女人不知道怎麼回事，瞬間就追上來了……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NPC_NULL","text":{"KOREA":"알아. 내가 둘의 흔적을 슬~쩍 남겼었거든!","JPN":"そりゃ、わかるよ。だってアタシが二人の痕跡をこっそり残しておいたんだもん！","ENG":"I know. I left a trail on purpose!","TWN":"我知道。是我偷偷留下痕跡的！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_SCISSORS_IN_TRAILER_6"},{"id":"L2_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_B","text":{"KOREA":"……예?","JPN":"……はい？","ENG":"...You what?","TWN":"……嗯？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_B","text":{"KOREA":"커…억… 보스……?","JPN":"か、はっ……ボス……？","ENG":"Kuuh... Boss...?","TWN":"咳……呃……老大……？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_B","text":{"KOREA":"왜…….","JPN":"なぜ……","ENG":"Why...?","TWN":"為什麼……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"이, 이게 무슨…….","JPN":"い、いったい……","ENG":"W-why did you...","TWN":"這、這算什麼……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NPC_NULL","text":{"KOREA":"응. 재미없으니까 해산. 조직도 이제 끝이야!","JPN":"うん。つまんないから解散。組織はもうおしまい！","ENG":"This is boring. The gang's disbanded!","TWN":"嗯。沒意思，解散吧。組織也到此為止了！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NPC_NULL","face":"UNIT_PRIDE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_SCISSORS_IN_TRAILER_7"},{"id":"L9_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NPC_NULL","text":{"KOREA":"애초에 너희, 너무 약해! 저쪽 단장이 얼마나 강한지 보려고 했는데 전혀 쓸모없잖아?","JPN":"そもそも～、君たち弱すぎ！　あっちの団長はどれぐらい強いのか確かめたかったのに、全然役に立たないじゃん。","ENG":"You losers are too weak! I just wanted to see how strong their captain was, but you were useless.","TWN":"你們一開始就太弱了！我本來想看看那邊的團長有多強，結果一點用都沒有？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NPC_NULL","face":"UNIT_LAUGH"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_SCISSORS_IN_TRAILER_8"},{"id":"L10_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NPC_NULL","text":{"KOREA":"아, 에스테리사? 에스테론… 아무튼, 걔도 약했으니 상관없나~?","JPN":"あ、エステリサ？　エステロン……とにかく、あいつも弱かったし、別にいいのかな～？","ENG":"Uh, Esterisa? Esteron...? Whatever. She was weak too, so who cares?","TWN":"啊，艾斯特麗莎？艾斯特隆……不管怎樣，她也很弱，沒關係吧～？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_SCISSORS_IN_TRAILER_9"},{"id":"L11_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NPC_NULL","text":{"KOREA":"설마 그 정도로 약해졌을 줄 몰랐어! 전력일때 싸워보고 싶었는데~ 아쉽다!","JPN":"まさかあんなに弱くなってるとは思わなかった！　万全のときに戦ってみたかったのに……残念～！","ENG":"Didn't think she'd be that much of a pushover. I wanted to fight her at full strength. What a shame.","TWN":"沒想到你竟然變得這麼弱！我還想和你全力一戰呢～真可惜！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NPC_NULL","face":"UNIT_LAUGH"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_SCISSORS_IN_TRAILER_10"},{"id":"L12_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NPC_NULL","text":{"KOREA":"아니, 우리한테는 좋은 건가?","JPN":"てか、こっちには好都合？","ENG":"Or maybe that works in our favor?","TWN":"不是，對我們來說是好事嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NPC_NULL","face":"UNIT_PRIDE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_SCISSORS_IN_TRAILER_11"},{"id":"L13_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"이 미친년이… 혼자 뭐라고 떠드는 거야?","JPN":"こいつ……一人で何ブツブツ言ってんだ？","ENG":"You psycho... What the heck are you even talking about?","TWN":"這個瘋女人……一個人在胡說些什麼？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"우리가 대체 뭘 잘못했다고…!!","JPN":"俺たちが何をやったっていうんだ……！！","ENG":"What did we do to deserve this...?!","TWN":"我們到底做錯了什麼……！！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NPC_NULL","text":{"KOREA":"적반하장 뭐시기야~! 아저씨는 날 배신하려 했잖아?","JPN":"逆ギレもいいとこだよ～！　おじさんはアタシを裏切ろうとしたじゃない？","ENG":"Don't flip it on me! You were gonna betray me, weren't you?","TWN":"真是賊喊捉賊啊～！叔叔你不是想背叛我嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_SCISSORS_IN_TRAILER_12"},{"id":"L16_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NPC_NULL","text":{"KOREA":"물론, 배신 안 했어도 죽일 거였지만. 원래 처음부터 다 죽일 생각이었거든~.","JPN":"もちろん、裏切らなくても殺してたけど。最初から全部殺すつもりだったんだよね～","ENG":"Not that it matters, since I was gonna kill you anyway. Always planned to!","TWN":"當然，就算不背叛也會殺掉他們。因為從一開始就打算全部殺掉～"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NPC_NULL","face":"UNIT_PRIDE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_SCISSORS_IN_TRAILER_13"},{"id":"L17_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NPC_NULL","text":{"KOREA":"내 비위 맞추느라 고생 많았어?","JPN":"アタシの機嫌取り、ごくろうさま！","ENG":"Thanks for entertaining me, though!","TWN":"為了迎合我，辛苦你了？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NPC_NULL","face":"UNIT_LAUGH"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_SCISSORS_IN_TRAILER_14"},{"id":"L18_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"이… 이…….","JPN":"この……この………","ENG":"Y-you...","TWN":"這、這……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"이 개년이이이이-!!","JPN":"このクソが……！！","ENG":"You wench!!","TWN":"你這個賤女人——！！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L27_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NPC_NULL","text":{"KOREA":"카란티시르 단장님. 임무 클리어예요~!","JPN":"カランティシル団長。任務クリアで～す！","ENG":"Captain Carantisir. Mission complete!","TWN":"卡蘭堤西爾團長，任務完成了喔～"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NPC_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L28_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NPC_NULL","text":{"KOREA":"그런데 못 참고 전부 죽여버렸어! 괜찮아?","JPN":"でも我慢できなくて全部殺しちゃった！　平気？","ENG":"Though I kinda lost control and killed everyone! Hope that's okay?","TWN":"但是我忍不住把他們全殺了！沒關係嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>문제없다, 아셀라 경. 어차피 인륜을 저버린 천한 것들이 아니었는가.</color>","JPN":"<color=#ffd34c>問題ない、アセッラ卿。どうせ人道に反する、下賤なやつらではなかったか。</color>","ENG":"<color=#ffd34c>No issue, Dame Ascella. They were just base scum who'd forsaken humanity.</color>","TWN":"<color=#ffd34c>沒問題，亞瑟拉。反正那些都是背棄人倫的卑賤之物。</color>"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L31_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>신분조차 천한 것들이었으니. 그대가 신경 쓸 문제는 아니다.</color>","JPN":"<color=#ffd34c>身分でさえそうなんだ。そなたが気にすることはない。</color>","ENG":"<color=#ffd34c>Lowborn filth. Nothing worth your concern.</color>","TWN":"<color=#ffd34c>身份卑微之輩。你無需費心。</color>"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"와~. 그럼 알아낼 것 전부 알아냈으니, 이제 아스테론이랑 싸우러 가도 돼?","JPN":"わ～じゃあもう調べ終わったから、アステロンと戦いに行ってもいい？","ENG":"Wow! Does that means I can finally go fight Astheron now?","TWN":"哇～那麼既然已經查清楚所有事情，現在可以去和阿斯特隆戰鬥了嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"나, 그쪽 단장님이랑 싸워보고 싶어!","JPN":"アタシ、そっちの団長と戦ってみたいの！","ENG":"I really wanna face their captain!","TWN":"我想和那邊的團長打一場！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>…….</color>","JPN":"<color=#ffd34c>……</color>","ENG":"<color=#ffd34c>...</color>","TWN":"<color=#ffd34c>……</color>"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>내가 그리 명했던가?</color>","JPN":"<color=#ffd34c>俺がそう命じたか？</color>","ENG":"<color=#ffd34c>Did I give you such an order?</color>","TWN":"<color=#ffd34c>我有要你去嗎？</color>"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"아.","JPN":"あ。","ENG":"Ah.","TWN":"啊。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"죄, 죄송해요. 흥분~? 흥분. 네, 그걸 해버렸나~?","JPN":"ご、ごめんなさい。興奮～？　興奮。はい、それやっちゃったかな～？","ENG":"S-sorry. E-excited? Yes, I might've gotten a little too excited.","TWN":"對、對不起。是我太興奮～？對，所以才逾矩的？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"아무튼 잘못했어요…….","JPN":"とにかく、ごめんなさい……","ENG":"Anyway, I'm sorry...","TWN":"總之，對不起……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>괜찮다. 부하의 모자람을 꾸짖는 것 또한 단장으로서의 덕목이니.</color>","JPN":"<color=#ffd34c>いい。部下の至らぬ点を指摘することもまた、団長の努め。</color>","ENG":"<color=#ffd34c>It's fine. As captain, it is my duty to guide my subordinates.</color>","TWN":"<color=#ffd34c>沒關係。責備下屬的不足也是作為團長的美德。</color>"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>곧 마음껏 날뛰게 해줄 테니, 너무 걱정 말도록.</color>","JPN":"<color=#ffd34c>もうすぐ好きなだけ暴れさせてやるから、心配するな。</color>","ENG":"<color=#ffd34c>You'll have your chance to rampage soon enough. Be patient.</color>","TWN":"<color=#ffd34c>很快就能讓你盡情撒野了，別太擔心。</color>"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"네~엡!","JPN":"は～い！","ENG":"Yes, sir!","TWN":"是～明白！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"단장님의 명령, 제대로 완수할게요?","JPN":"団長の命令、ちゃんと完遂する！","ENG":"I'll carry out your next order perfectly!","TWN":"團長的命令，我會好好完成的？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>그래, 기대하지.</color>","JPN":"<color=#ffd34c>ああ、期待しよう。</color>","ENG":"<color=#ffd34c>Good. I look forward to it.</color>","TWN":"<color=#ffd34c>好，那我拭目以待。</color>"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"헤헤. 곧 파란~? 파아란 녀석들이랑 만나겠네.","JPN":"えへへ。もうすぐ青い～？　青い奴らと会えるなあ。","ENG":"Hehe. The Blueys? We'll soon get to meet the blueys soon.","TWN":"嘿嘿。馬上就要和藍色～？藍色的傢伙們見面了呢。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02","voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_SCISSORS_IN_TRAILER_15"},{"id":"L50_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"그쪽 애들은 얼마나 강할지, 기대된다~.","JPN":"そっちの子はどれぐらい強いんだろ、楽しみ～","ENG":"I wonder how strong they really are. I can't wait!","TWN":"那些傢伙會有多強呢，真讓人期待~。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_SCISSORS_IN_TRAILER_16"}]`);export{e as default};